module up_down_counter (
        input rst,
        input up,
        input reset,
        output reg [3:0] q);

    always @(posedge rst or posedge reset) begin
        if (reset)
            q <= 4'b0000;
        else if (up)
            q <= q + 1;
        else
            q <= q - 1;
    end

endmodule
